import { useState } from 'react';
import { format } from 'date-fns';
import './App.css';
import Api from './axios/api';

interface Usuario {
  id: number;
  nome: string;
  cpf: string;
  telefone: string;
  dia_agendado: string;
  hora_agendada:string;
  data:string;
  status: string;
}

function App() {
const [usuarios, setUsuarios] =useState<Usuario[]>([{} as Usuario]);
  const formattedDate = format(new Date().toLocaleString(), 'MMMM do, yyyy ');
const BuscarTodosUsuarios= async () => {
  console.log("Buscando todos os usuários...");
 await Api.get("",{
    params:{
    planilha:"usuario"
  }
  }
).then((response)=>setUsuarios(response.data) )  
  .catch((e)=> console.log(e));
  console.log("Usuários encontrados:");

}
return (
    <div style={{display:'flex',flexDirection:"column"}}>
      <h1>Hello Mumi Braids!</h1>
      <h4> Site de Agendamento</h4>      
   <table border={1} width="80%" style={{margin:10}} summary='Tabela de usuários'>
<thead>
 <tr>
    <th>Nome</th>     
    <th>CPF</th>
    <th>Telefone</th>
    <th>Dia Agendado</th>
    <th>Hora Agendada</th>
    <th>Data</th>
    <th>Status</th>
    </tr>
</thead>
<tbody>
  {usuarios.map((usuario) => (   
    <tr>    
      <td>{usuario.nome}</td>
      <td>{usuario.cpf}</td>
      <td>{usuario.telefone}</td>
      <td>{format(usuario.dia_agendado, 'MMMM do, yyyy')}</td>
      <td>{usuario.hora_agendada}</td>
      <td>{usuario.status}</td>
      </tr>

  ))}
</tbody>
   </table>
    <div>
      <button onClick={BuscarTodosUsuarios}>  Visuaisar</button>
      </div>

    </div> 
  );
}

export default App;
